
import {Callback} from './PromiseUtils';
import * as events from 'events';
const uuid = require('uuid');
import JiboLog = require('jibo-log'); // Only for type, shouldn't create `require`

export type OpenMethod = (options: any) => Activity;

export interface Activity {
    promise: Promise<any>;
    stop: () => any | Promise<any>;
    update?: Callback<any>;
}

export class Session {
    id: string = uuid.v4();
    active = false;
    hasBeenStopped = false;
    activity: Activity;

    constructor(public options: any) { }

    /**
     * Stops the session activity if possible
     * @returns {(any | Promise<any>)} 
     * @memberOf Session
     */
    stop(): any | Promise<any> {
        if (!this.hasBeenStopped && this.activity) {
            this.hasBeenStopped = true;
            return this.activity.stop();
        }
    }

    /**
     * Updates the session activity if possible
     * @memberOf Session
     */
    update(): void {
        if (this.activity && this.activity.update) {
            this.activity.update();
        }
    }
}

export class SessionManager {

    public current: Session;
    private pending: Session;
    private isClosing = false;
    private emitter = new events.EventEmitter();
    
    /**
     * Creates an instance of SessionManager.
     * @param {OpenMethod} openMethod - Is called to create a new session
     * @param {() => void} done - Gets called when all sessions have completed 
     * @param {JiboLog} [logger] optional logger implementation 
     * @memberOf SessionManager
     */
    constructor(private openMethod: OpenMethod,
        private done: () => void,
        private logger?: JiboLog) { 
        // noop
    }

    /**
     * Should be called when skill is opened
     * @memberOf SessionManager
     */
    public open(options: any) {
        if (this.current) {
            this.current.active = false;
        }
        this.current = null;
        this.pending = null;
        this.isClosing = false;
        this.emitter.removeAllListeners();

        this.replaceSession(options);
    }

    /**
     * Switches skill session
     * @param {*} options
     * @memberOf SessionManager
     */
    public replaceSession(options: any): void {
        const session = new Session(options);

        if (this.current) {
            // If we have a current session, we set this as pending and tell current session to stop
            this.pending = session;
            this.current.stop();
        } else {
            // We immediately open this session
            this._startSession(session);
        }
    }

    /**
     * Stops current session and waits for it to finish.
     * After any call to this method you have to call `open` again
     * @returns {Promise<any>}
     * @memberOf SessionManager
     */
    public close(): Promise<any> {
        this.isClosing = true;
        this.pending = null;
        let pr = Promise.resolve();
        if (this.current) {
            const ret = this.current.stop();
            if (ret instanceof Promise) {
                pr = ret as Promise<any>;
            }
        }
        return pr.then(() => this.waitForCurrent());
    }

    /**
     * Waits for the current session to complete, if no session is current then we resolve immediately
     * @returns {Promise<any>}
     * @memberOf SessionManager
     */
    public waitForCurrent(): Promise<any> {
        if (this.current) {
            return this.current.activity.promise;
        } else {
            return Promise.resolve();
        }
    }

    /**
     * Waits for all sessions to complete, if no session is current then we resolve immediately
     * @returns {Promise<any>}
     * @memberOf SessionManager
     */
    public waitForAll(): Promise<any> {
        if (this.current) {
            return new Promise(resolve => {
                this.emitter.once('done', resolve);
            });
        } else {
            return Promise.resolve();
        }
    }

    private _startSession(session: Session) {
        this.current = session;
        session.active = true;
        session.activity = this.openMethod(session.options);
        session.activity.promise = session.activity.promise
            .catch(err => this.errorLog(err))
            .then(() => {
                // If this session is the current one, then we set it to null
                if (this.current === session) {
                    this.current = null;
                }
                session.active = false;
                // If there is a pending session, we open that one
                if (this.pending) {
                    const next = this.pending;
                    this.pending = null;
                    this._startSession(next);
                } else {
                    // If we are not in the process of closing then we call the done callback
                    if (!this.isClosing) {
                        this.done();
                    }
                    this.emitter.emit('done');
                }
            });
    }

    /**
     * Prints error to log
     * @private
     * @param {*} msg 
     * @param {...any[]} args 
     * @memberOf SessionManager
     */
    private errorLog(msg:any, ...args: any[]) {
        if (this.logger) {
            this.logger.error(msg, ...args);
        } else {
            console.error(msg, ...args);
        }
    }
}